// ============================================================
// typelist.hpp — Compile-Time Type List Library
// Case Study 4 for "Claude Code + C++ Software Design" paper
// Generated by Claude Code, reviewed and revised by 赵鑫
//
// Tests Claude Code's limits on:
//   - Variadic template recursion
//   - SFINAE / std::enable_if / C++20 requires (partial)
//   - constexpr computation
//   - Complex template partial specialization
//   - Fold expressions (C++17)
// ============================================================

#pragma once

#include <cstddef>
#include <type_traits>
#include <utility>
#include <tuple>

namespace cccs {

// ============================================================
// 1. TypeList definition
// ============================================================
template<typename... Ts>
struct TypeList {
    static constexpr size_t size = sizeof...(Ts);
};

// ============================================================
// 2. Basic operations: Front, PopFront, PushFront, PushBack
// ============================================================

// Front: get the first type
template<typename List>
struct Front;

template<typename T, typename... Ts>
struct Front<TypeList<T, Ts...>> {
    using type = T;
};

template<typename List>
using Front_t = typename Front<List>::type;

// PopFront: remove the first type
template<typename List>
struct PopFront;

template<typename T, typename... Ts>
struct PopFront<TypeList<T, Ts...>> {
    using type = TypeList<Ts...>;
};

template<typename List>
using PopFront_t = typename PopFront<List>::type;

// PushFront: prepend a type
template<typename List, typename T>
struct PushFront;

template<typename... Ts, typename T>
struct PushFront<TypeList<Ts...>, T> {
    using type = TypeList<T, Ts...>;
};

template<typename List, typename T>
using PushFront_t = typename PushFront<List, T>::type;

// PushBack: append a type
template<typename List, typename T>
struct PushBack;

template<typename... Ts, typename T>
struct PushBack<TypeList<Ts...>, T> {
    using type = TypeList<Ts..., T>;
};

template<typename List, typename T>
using PushBack_t = typename PushBack<List, T>::type;

// ============================================================
// 3. Advanced: NthType, Contains, IndexOf, AllOf, AnyOf
// ============================================================

// NthType: get type at index N (0-based)
template<typename List, size_t N>
struct NthType;

template<typename T, typename... Ts>
struct NthType<TypeList<T, Ts...>, 0> {
    using type = T;
};

template<typename T, typename... Ts, size_t N>
struct NthType<TypeList<T, Ts...>, N> {
    static_assert(N <= sizeof...(Ts), "Index out of bounds");
    using type = typename NthType<TypeList<Ts...>, N - 1>::type;
};

template<typename List, size_t N>
using NthType_t = typename NthType<List, N>::type;

// Contains: check if a type is in the list
template<typename List, typename Target>
struct Contains;

template<typename Target>
struct Contains<TypeList<>, Target> : std::false_type {};

// [CLAUDE CODE NOTE]: Original Claude Code output generated:
//   template<typename T, typename... Ts, typename Target>
//   struct Contains<TypeList<T, Ts...>, Target>
//       : std::conditional_t<std::is_same_v<T, Target>, std::true_type,
//           typename Contains<TypeList<Ts...>, Target>::type> {};
// This fails because std::conditional_t requires ::type to be complete.
// Fix applied manually by 赵鑫 (1 iteration).
template<typename T, typename... Ts, typename Target>
struct Contains<TypeList<T, Ts...>, Target> {
    static constexpr bool value =
        std::is_same_v<T, Target> || Contains<TypeList<Ts...>, Target>::value;
};

template<typename List, typename Target>
inline constexpr bool Contains_v = Contains<List, Target>::value;

// IndexOf: find the first index of Target, or -1 if not found
template<typename List, typename Target, size_t Offset = 0>
struct IndexOf;

template<typename Target, size_t Offset>
struct IndexOf<TypeList<>, Target, Offset> {
    static constexpr int value = -1;
};

template<typename T, typename... Ts, typename Target, size_t Offset>
struct IndexOf<TypeList<T, Ts...>, Target, Offset> {
    static constexpr int value =
        std::is_same_v<T, Target> ? static_cast<int>(Offset)
            : IndexOf<TypeList<Ts...>, Target, Offset + 1>::value;
};

template<typename List, typename Target>
inline constexpr int IndexOf_v = IndexOf<List, Target>::value;

// AllOf: check if all types satisfy a predicate
template<typename List, template<typename> typename Predicate>
struct AllOf;

template<template<typename> typename Predicate>
struct AllOf<TypeList<>, Predicate> : std::true_type {};

template<typename T, typename... Ts, template<typename> typename Predicate>
struct AllOf<TypeList<T, Ts...>, Predicate> {
    static constexpr bool value =
        Predicate<T>::value && AllOf<TypeList<Ts...>, Predicate>::value;
};

template<typename List, template<typename> typename Predicate>
inline constexpr bool AllOf_v = AllOf<List, Predicate>::value;

// AnyOf: check if any type satisfies a predicate
template<typename List, template<typename> typename Predicate>
struct AnyOf;

template<template<typename> typename Predicate>
struct AnyOf<TypeList<>, Predicate> : std::false_type {};

template<typename T, typename... Ts, template<typename> typename Predicate>
struct AnyOf<TypeList<T, Ts...>, Predicate> {
    static constexpr bool value =
        Predicate<T>::value || AnyOf<TypeList<Ts...>, Predicate>::value;
};

template<typename List, template<typename> typename Predicate>
inline constexpr bool AnyOf_v = AnyOf<List, Predicate>::value;

// ============================================================
// 4. Transform, Filter, Reverse (advanced recursion)
// ============================================================

// Transform: apply a meta-function to each type
template<typename List, template<typename> typename F>
struct Transform;

template<template<typename> typename F>
struct Transform<TypeList<>, F> {
    using type = TypeList<>;
};

template<typename T, typename... Ts, template<typename> typename F>
struct Transform<TypeList<T, Ts...>, F> {
    using type = PushFront_t<typename Transform<TypeList<Ts...>, F>::type,
                              typename F<T>::type>;
};

template<typename List, template<typename> typename F>
using Transform_t = typename Transform<List, F>::type;

// [CLAUDE CODE NOTE]: Claude Code v2 generated a version using
// fold expressions for Filter — but fold expressions on template
// parameter packs with conditional type inclusion require C++20
// template lambdas and are not valid in C++17. Manual rewrite
// to recursive SFINAE pattern by 赵鑫 (2 iterations).

// Filter: keep types satisfying a predicate
template<typename List, template<typename> typename Predicate>
struct Filter;

template<template<typename> typename Predicate>
struct Filter<TypeList<>, Predicate> {
    using type = TypeList<>;
};

template<typename T, typename... Ts, template<typename> typename Predicate>
struct Filter<TypeList<T, Ts...>, Predicate> {
    using filtered_tail = typename Filter<TypeList<Ts...>, Predicate>::type;
    using type = std::conditional_t<
        Predicate<T>::value,
        PushFront_t<filtered_tail, T>,
        filtered_tail
    >;
};

template<typename List, template<typename> typename Predicate>
using Filter_t = typename Filter<List, Predicate>::type;

// Reverse: reverse the type list
template<typename List>
struct Reverse {
    using type = typename Reverse<PopFront_t<List>>::type;
    // Note: this base case is intentionally left to specialization
};

template<>
struct Reverse<TypeList<>> {
    using type = TypeList<>;
};

template<typename T, typename... Ts>
struct Reverse<TypeList<T, Ts...>> {
private:
    using reversed_tail = typename Reverse<TypeList<Ts...>>::type;
public:
    using type = PushBack_t<reversed_tail, T>;
};

template<typename List>
using Reverse_t = typename Reverse<List>::type;

// ============================================================
// 5. Sort, Unique, Concatenate (complex multi-pass operations)
// ============================================================

// Concatenate: join two TypeLists
template<typename L1, typename L2>
struct Concatenate;

template<typename... Ts1, typename... Ts2>
struct Concatenate<TypeList<Ts1...>, TypeList<Ts2...>> {
    using type = TypeList<Ts1..., Ts2...>;
};

template<typename L1, typename L2>
using Concatenate_t = typename Concatenate<L1, L2>::type;

// GetSize: compute total bytes of types (demonstrates constexpr fold)
template<typename List>
struct GetSize;

template<typename... Ts>
struct GetSize<TypeList<Ts...>> {
    static constexpr size_t value = (sizeof(Ts) + ...);  // C++17 fold
};

template<typename List>
inline constexpr size_t GetSize_v = GetSize<List>::value;

// ============================================================
// 6. Predicate templates for testing
// ============================================================

template<typename T>
using IsIntegral = std::is_integral<T>;

template<typename T>
using IsFloatingPoint = std::is_floating_point<T>;

template<typename T>
using IsPointer = std::is_pointer<T>;

template<typename T>
using AddConst = std::add_const<T>;

template<typename T>
using RemovePointer = std::remove_pointer_t<T>;

} // namespace cccs
